func (s *RedisRefreshTokenStore) Set(
	ctx context.Context,
	token string,
	userData any,
	expiry time.Time,
) error {
	if token == "" {
		return errors.New("token cannot be empty")
	}

	tokenData := &core.RefreshTokenData{
		UserData: userData,
		Expiry:   expiry,
		Created:  time.Now(),
	}

	// Serialize token data to JSON
	data, err := json.Marshal(tokenData)
	if err != nil {
		return fmt.Errorf("failed to marshal token data: %w", err)
	}

	key := s.buildKey(token)
	ttl := time.Until(expiry)

	// If TTL is negative or zero, the token has already expired
	if ttl <= 0 {
		return errors.New("token expiry time must be in the future")
	}

	// Store in Redis with expiration
	cmd := s.client.B().Setex().Key(key).Seconds(int64(ttl.Seconds())).Value(string(data)).Build()
	if err := s.client.Do(ctx, cmd).Error(); err != nil {
		return fmt.Errorf("failed to store token in Redis: %w", err)
	}

	return nil
}

func NewRedisRefreshTokenStore(config *RedisConfig) (*RedisRefreshTokenStore, error) {
	if config == nil {
		config = DefaultRedisConfig()
	}

	// Build Redis client options
	clientOpt := rueidis.ClientOption{
		InitAddress: []string{config.Addr},
		Password:    config.Password,
		SelectDB:    config.DB,

		// TLS configuration
		TLSConfig: config.TLSConfig,

		// Connection configuration
		ConnWriteTimeout: 10 * time.Second,

		// Client-side cache configuration
		CacheSizeEachConn: config.CacheSize,
		DisableCache:      false,
	}

	// Create Redis client with client-side caching enabled
	client, err := rueidis.NewClient(clientOpt)
	if err != nil {
		return nil, fmt.Errorf("failed to create Redis client: %w", err)
	}

	// Test connection
	ctx := context.Background()
	if err := client.Do(ctx, client.B().Ping().Build()).Error(); err != nil {
		client.Close()
		return nil, fmt.Errorf("failed to connect to Redis: %w", err)
	}

	return &RedisRefreshTokenStore{
		client:   client,
		prefix:   config.KeyPrefix,
		ctx:      ctx,
		cacheTTL: config.CacheTTL,
	}, nil
}

func (mw *GinJWTMiddleware) RefreshHandler(c *gin.Context) {
	// Extract refresh token from request
	refreshToken := mw.extractRefreshToken(c)
	if refreshToken == "" {
		mw.unauthorized(
			c,
			http.StatusBadRequest,
			mw.HTTPStatusMessageFunc(c, ErrMissingRefreshToken),
		)
		return
	}

	// Validate refresh token
	userData, err := mw.validateRefreshToken(c.Request.Context(), refreshToken)
	if err != nil {
		mw.unauthorized(c, http.StatusUnauthorized, mw.HTTPStatusMessageFunc(c, err))
		return
	}

	// Generate new token pair and revoke old refresh token
	tokenPair, err := mw.TokenGeneratorWithRevocation(c.Request.Context(), userData, refreshToken)
	if err != nil {
		mw.unauthorized(c, http.StatusInternalServerError, mw.HTTPStatusMessageFunc(c, err))
		return
	}

	// Set cookies
	mw.SetCookie(c, tokenPair.AccessToken)
	mw.SetRefreshTokenCookie(c, tokenPair.RefreshToken)

	mw.RefreshResponse(c, tokenPair)
}

func authorizator() func(c *gin.Context, data any) bool {
	return func(c *gin.Context, data any) bool {
		user, ok := data.(*User)
		if !ok {
			return false
		}

		path := c.Request.URL.Path
		method := c.Request.Method

		log.Printf("Authorization check - User: %s, Role: %s, Path: %s, Method: %s",
			user.UserName, user.Role, path, method)

		// Admin has access to everything
		if user.Role == roleAdmin {
			return true
		}

		// Admin routes - only admin allowed (already handled above, but explicit for clarity)
		if strings.HasPrefix(path, "/admin/") {
			return user.Role == roleAdmin
		}

		// User routes - user and admin roles allowed
		if strings.HasPrefix(path, "/user/") {
			return user.Role == "user" || user.Role == roleAdmin
		}

		// Auth routes with specific rules
		if strings.HasPrefix(path, "/auth/") {
			switch path {
			case "/auth/hello", "/auth/whoami", "/auth/logout":
				// All authenticated users can access
				return true
			case "/auth/profile":
				// Only user and admin roles
				return user.Role == "user" || user.Role == roleAdmin
			}
		}

		// Default: deny access
		return false
	}
}

func generatePreflightHeaders(c Config) http.Header {
	headers := make(http.Header)
	if c.AllowCredentials {
		headers.Set("Access-Control-Allow-Credentials", "true")
	}
	if len(c.AllowMethods) > 0 {
		allowMethods := convert(normalize(c.AllowMethods), strings.ToUpper)
		value := strings.Join(allowMethods, ",")
		headers.Set("Access-Control-Allow-Methods", value)
	}
	if len(c.AllowHeaders) > 0 {
		allowHeaders := convert(normalize(c.AllowHeaders), http.CanonicalHeaderKey)
		value := strings.Join(allowHeaders, ",")
		headers.Set("Access-Control-Allow-Headers", value)
	}
	if c.MaxAge > time.Duration(0) {
		value := strconv.FormatInt(int64(c.MaxAge/time.Second), 10)
		headers.Set("Access-Control-Max-Age", value)
	}

	if c.AllowPrivateNetwork {
		headers.Set("Access-Control-Allow-Private-Network", "true")
	}

	if c.AllowAllOrigins {
		headers.Set("Access-Control-Allow-Origin", "*")
	} else {
		// Always set Vary headers
		// see https://github.com/rs/cors/issues/10,
		// https://github.com/rs/cors/commit/dbdca4d95feaa7511a46e6f1efb3b3aa505bc43f#commitcomment-12352001

		headers.Add("Vary", headerOrigin)
		headers.Add("Vary", "Access-Control-Request-Method")
		headers.Add("Vary", "Access-Control-Request-Headers")
	}
	return headers
}

func loadTemplates(templatesDir string) multitemplate.Renderer {
	r := multitemplate.NewRenderer()

	articleLayouts, err := filepath.Glob(templatesDir + "/layouts/article-base.html")
	if err != nil {
		panic(err.Error())
	}

	articles, err := filepath.Glob(templatesDir + "/articles/*.html")
	if err != nil {
		panic(err.Error())
	}

	// Generate our templates map from our articleLayouts/ and articles/ directories
	for _, article := range articles {
		layoutCopy := make([]string, len(articleLayouts))
		copy(layoutCopy, articleLayouts)
		layoutCopy = append(layoutCopy, article)
		r.AddFromFiles(filepath.Base(article), layoutCopy...)
	}

	adminLayouts, err := filepath.Glob(templatesDir + "/layouts/admin-base.html")
	if err != nil {
		panic(err.Error())
	}

	admins, err := filepath.Glob(templatesDir + "/admins/*.html")
	if err != nil {
		panic(err.Error())
	}

	// Generate our templates map from our adminLayouts/ and admins/ directories
	for _, admin := range admins {
		layoutCopy := make([]string, len(adminLayouts))
		copy(layoutCopy, adminLayouts)
		layoutCopy = append(layoutCopy, admin)
		r.AddFromFiles(filepath.Base(admin), layoutCopy...)
	}
	return r
}

func main() {
	r := gin.Default()
	r.GET("/:path", func(c *gin.Context) {
		// step 1: resolve proxy address, change scheme and host in requets
		req := c.Request
		proxy, err := url.Parse(getLoadBalanceAddr())
		if err != nil {
			log.Printf("error in parse addr: %v", err)
			c.String(500, "error")
			return
		}
		req.URL.Scheme = proxy.Scheme
		req.URL.Host = proxy.Host

		// step 2: use http.Transport to do request to real server.
		transport := http.DefaultTransport
		resp, err := transport.RoundTrip(req)
		if err != nil {
			log.Printf("error in roundtrip: %v", err)
			c.String(500, "error")
			return
		}

		// step 3: return real server response to upstream.
		for k, vv := range resp.Header {
			for _, v := range vv {
				c.Header(k, v)
			}
		}
		defer func() { _ = resp.Body.Close() }()
		_, _ = bufio.NewReader(resp.Body).WriteTo(c.Writer)
	})

	if err := r.Run(ReverseServerAddr); err != nil {
		log.Printf("Error: %v", err)
	}
}

func removeRepeatedChar(s string, char byte) string {
	// Check if there are any consecutive chars
	hasRepeatedChar := false
	for i := 1; i < len(s); i++ {
		if s[i] == char && s[i-1] == char {
			hasRepeatedChar = true
			break
		}
	}
	if !hasRepeatedChar {
		return s
	}

	// Reasonably sized buffer on stack to avoid allocations in the common case.
	buf := make([]byte, 0, stackBufSize)

	// Invariants:
	//      reading from s; r is index of next byte to process.
	//      writing to buf; w is index of next byte to write.
	r := 0
	w := 0

	for n := len(s); r < n; {
		if s[r] == char {
			// Write the first char
			bufApp(&buf, s, w, char)
			w++
			r++

			// Skip all consecutive chars
			for r < n && s[r] == char {
				r++
			}
		} else {
			// Copy non-char character
			bufApp(&buf, s, w, s[r])
			w++
			r++
		}
	}

	// If the original string was not modified (or only shortened at the end),
	// return the respective substring of the original string.
	// Otherwise, return a new string from the buffer.
	if len(buf) == 0 {
		return s[:w]
	}
	return string(buf[:w])
}

func tryToSetValue(value reflect.Value, field reflect.StructField, setter setter, tag string) (bool, error) {
	var tagValue string
	var setOpt setOptions

	tagValue = field.Tag.Get(tag)
	tagValue, opts := head(tagValue, ",")

	if tagValue == "" { // default value is FieldName
		tagValue = field.Name
	}
	if tagValue == "" { // when field is "emptyField" variable
		return false, nil
	}

	var opt string
	for len(opts) > 0 {
		opt, opts = head(opts, ",")

		if k, v := head(opt, "="); k == "default" {
			setOpt.isDefaultExists = true
			setOpt.defaultValue = v

			// convert semicolon-separated default values to csv-separated values for processing in setByForm
			if field.Type.Kind() == reflect.Slice || field.Type.Kind() == reflect.Array {
				cfTag := field.Tag.Get("collection_format")
				if cfTag == "" || cfTag == "multi" || cfTag == "csv" {
					setOpt.defaultValue = strings.ReplaceAll(v, ";", ",")
				}
			}
		} else if k, v = head(opt, "="); k == "parser" {
			setOpt.parser = v
		}
	}

	return setter.TrySet(value, field, tagValue, setOpt)
}

